<script setup lang="ts">
import{computed,onMounted,ref,watch}from'vue';import{useI18n}from'vue-i18n';import{getSubtitleConfig,getSubtitleFonts,saveSubtitleConfig,startSubtitlePositioning}from'@/api/subtitles';import{useSubtitlePreview}from'@/composables/useSubtitlePreview';import{useUnsavedChanges}from'@/composables/useUnsavedChanges';import SubtitleAppearanceControls from'@/components/SubtitleAppearanceControls.vue';import SubtitleBehaviorControls from'@/components/SubtitleBehaviorControls.vue';import SubtitlePositionControls from'@/components/SubtitlePositionControls.vue';import SubtitlePreview from'@/components/SubtitlePreview.vue';import SubtitleTypographyControls from'@/components/SubtitleTypographyControls.vue';import type{SubtitleConfig}from'@/types/subtitles'
const{t}=useI18n();const config=ref<SubtitleConfig|null>(null),baseline=ref(''),fonts=ref<string[]>([]),loading=ref(true),saving=ref(false),fontsBusy=ref(false),positioningBusy=ref(false),error=ref(''),success=ref(''),positioning=ref(false);const clone=(value:SubtitleConfig)=>JSON.parse(JSON.stringify(value)) as SubtitleConfig;const dirty=computed(()=>!!config.value&&JSON.stringify(config.value)!==baseline.value);useUnsavedChanges(dirty,()=>t('subtitles.unsavedConfirm'));const preview=useSubtitlePreview();
async function load(){loading.value=true;error.value='';try{config.value=await getSubtitleConfig();baseline.value=JSON.stringify(config.value);preview.schedule(clone(config.value))}catch(e){error.value=e instanceof Error?e.message:''}finally{loading.value=false}}async function refreshFonts(){if(fontsBusy.value)return;fontsBusy.value=true;try{fonts.value=(await getSubtitleFonts()).fonts}catch(e){error.value=e instanceof Error?e.message:''}finally{fontsBusy.value=false}}async function save(){if(!config.value||saving.value)return;saving.value=true;error.value='';success.value='';try{config.value=await saveSubtitleConfig(config.value);baseline.value=JSON.stringify(config.value);success.value=t('subtitles.saved')}catch(e){error.value=e instanceof Error?e.message:''}finally{saving.value=false}}function reset(){if(baseline.value)config.value=JSON.parse(baseline.value) as SubtitleConfig;success.value=''}async function position(){if(positioningBusy.value)return;positioningBusy.value=true;error.value='';try{await startSubtitlePositioning();positioning.value=true;globalThis.setTimeout(()=>positioning.value=false,60000)}catch(e){error.value=e instanceof Error?e.message:''}finally{positioningBusy.value=false}}watch(config,v=>{if(v)preview.schedule(clone(v))},{deep:true});onMounted(()=>{void load();void refreshFonts()})
</script>
<template><section class="page subtitle-page"><header class="page-heading"><div><p class="eyebrow">{{t('subtitles.eyebrow')}}</p><h1>{{t('subtitles.title')}}</h1></div><div class="button-row"><button :disabled="!dirty||saving" @click="reset">{{t('subtitles.reset')}}</button><button class="primary-button" :disabled="!dirty||saving" @click="save">{{saving?t('subtitles.saving'):t('subtitles.save')}}</button></div></header><p class="platform-note">{{t('subtitles.windowsNote')}}</p><p v-if="loading">{{t('subtitles.loading')}}</p><p v-if="error" class="error-text">{{error}}</p><p v-if="success" class="success-text">{{success}}</p><template v-if="config"><SubtitlePreview :url="preview.url.value" :loading="preview.loading.value" :error="preview.error.value" @generate="preview.generate(clone(config))"/><section class="form-section"><header class="section-heading"><div><h2>{{t('subtitles.native.title')}}</h2><p>{{config.enabled?t('subtitles.native.enabled'):t('subtitles.native.disabled')}}</p></div><button class="primary-button" :disabled="positioningBusy||!config.enabled" @click="position">{{t('subtitles.native.position')}}</button></header><p v-if="positioning" role="status">{{t('subtitles.native.active')}}</p></section><SubtitlePositionControls v-model="config"/><SubtitleTypographyControls v-model="config" :fonts="fonts" :fonts-busy="fontsBusy" @refresh-fonts="refreshFonts"/><SubtitleAppearanceControls v-model="config"/><SubtitleBehaviorControls v-model="config"/></template></section></template>
